/*
 * SECURITY GATE — HMAC-SHA256 webhook signature verification
 * ──────────────────────────────────────────────────────────────────
 * Rejects any request whose x-webhook-signature header does
 * not match HMAC-SHA256(secret, rawBody).
 * Fails closed: missing signature = rejected.
 */

const crypto  = require('crypto');
const item    = $input.first().json;
const headers = item.headers ?? {};
const rawBody = item.rawBody  ?? JSON.stringify(item.body ?? item);

const secret    = process.env.WEBHOOK_SECRET;
const sigHeader = headers['x-webhook-signature'] ?? headers['x-hub-signature-256'] ?? '';

if (!secret) throw new Error('SECURITY_ERROR: WEBHOOK_SECRET env var not set');
if (!sigHeader) throw new Error('AUTH_ERROR: missing x-webhook-signature header');

const expected  = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
const sigBuffer = Buffer.from(sigHeader);
const expBuffer = Buffer.from(expected);

// Constant-time comparison to prevent timing attacks
if (sigBuffer.length !== expBuffer.length || !crypto.timingSafeEqual(sigBuffer, expBuffer)) {
  throw new Error(`AUTH_ERROR: invalid webhook signature`);
}

// ── Parse body ─────────────────────────────────────────────────────
const body = item.body ?? item;

// ── Event type normalisation ───────────────────────────────────────
const EVENT_MAP = {
  'contact.created': 'CONTACT_NEW',
  'contact.updated': 'CONTACT_UPDATE',
  'contact.deleted': 'CONTACT_DELETE',
  'deal.created':    'DEAL_NEW',
  'deal.updated':    'DEAL_UPDATE',
  'deal.won':        'DEAL_WON',
  'company.created': 'COMPANY_NEW'
};

const eventType = EVENT_MAP[body.event] ?? body.eventType ?? null;
if (!eventType) throw new Error(`VALIDATION_ERROR: unknown event type [${body.event}]`);

// ── Build canonical contact ────────────────────────────────────────
const src = body.contact ?? body.data ?? body;
const email = (src.email ?? '').toLowerCase().trim();
if (!email) throw new Error('VALIDATION_ERROR: contact.email is required');

const traceId = `tr-crm-${Date.now().toString(36)}-${Math.random().toString(36).slice(2,6)}`;

return [{
  json: {
    traceId,
    syncId:       `SYNC-${traceId}`,
    eventType,
    sourceSystem: body.source ?? headers['x-source-system'] ?? 'unknown',
    receivedAt:   new Date().toISOString(),

    contact: {
      externalId:     src.id          ?? src.contactId   ?? null,
      email,
      firstName:      src.firstName   ?? src.first_name  ?? '',
      lastName:       src.lastName    ?? src.last_name   ?? '',
      phone:          src.phone       ?? src.phoneNumber ?? null,
      company:        src.company     ?? src.companyName ?? null,
      jobTitle:       src.jobTitle    ?? src.job_title   ?? null,
      website:        src.website     ?? null,
      lifecycleStage: src.lifecycleStage ?? src.lifecycle_stage ?? 'lead',
      leadStatus:     src.leadStatus  ?? src.lead_status  ?? 'new',
      country:        src.country     ?? src.address?.country ?? null,
      city:           src.city        ?? src.address?.city    ?? null,
      customFields:   src.customFields ?? src.custom_fields   ?? {}
    },

    deal: body.deal ? {
      dealId:    body.deal.id,
      dealName:  body.deal.name,
      amount:    body.deal.amount    ?? 0,
      stage:     body.deal.stage     ?? 'prospecting',
      closeDate: body.deal.closeDate ?? null,
      currency:  body.deal.currency  ?? 'USD'
    } : null,

    // Sync state tracking
    destinations: { hubspot: 'pending', sheets: 'pending' },
    errors:       []
  }
}];

/*
 * HUBSPOT PAYLOAD TRANSFORMER
 * ──────────────────────────────────────────────────────────────────
 * Maps canonical contact schema → HubSpot CRM v3 properties.
 * Strips nulls (HubSpot rejects null values).
 * Determines PATCH vs POST based on externalId presence.
 */

const d = $input.first().json;
const c = d.contact;

const props = {
  email:              c.email,
  firstname:          c.firstName        || undefined,
  lastname:           c.lastName         || undefined,
  phone:              c.phone            || undefined,
  company:            c.company          || undefined,
  jobtitle:           c.jobTitle         || undefined,
  website:            c.website          || undefined,
  lifecyclestage:     c.lifecycleStage,
  hs_lead_status:     c.leadStatus?.toUpperCase() || undefined,
  country:            c.country          || undefined,
  city:               c.city             || undefined,
  // Audit trail properties (configure these in your HubSpot portal)
  n8n_trace_id:       d.traceId,
  n8n_sync_id:        d.syncId,
  n8n_source_system:  d.sourceSystem,
  n8n_synced_at:      d.receivedAt
};

// Remove undefined values
const cleanProps = Object.fromEntries(
  Object.entries(props).filter(([, v]) => v !== undefined && v !== null)
);

const isUpdate   = !!c.externalId;
const endpoint   = isUpdate
  ? `/crm/v3/objects/contacts/${c.externalId}`
  : '/crm/v3/objects/contacts';
const httpMethod = isUpdate ? 'PATCH' : 'POST';

return [{
  json: {
    ...d,
    hubspot: {
      endpoint,
      method:  httpMethod,
      payload: { properties: cleanProps }
    }
  }
}];

/*
 * HUBSPOT RESULT EVALUATOR
 * ──────────────────────────────────────────────────────────────────
 * Inspects the HTTP response and either:
 *  a) Attaches the HubSpot contact ID and marks success, or
 *  b) Records a structured error and marks failure.
 *
 * Tolerates 409 CONFLICT (contact already exists) as a soft success
 * — this is idempotent behaviour when the same contact arrives twice.
 */

const d          = $input.first().json;
const statusCode = d.statusCode ?? 0;
const body       = d.body ?? {};

const isSuccess  = statusCode >= 200 && statusCode <= 299;
const isConflict = statusCode === 409; // duplicate — treat as soft success

if (isSuccess || isConflict) {
  return [{
    json: {
      ...d,
      destinations: { ...d.destinations, hubspot: 'success' },
      hubspotContactId: body.id ?? body.vid ?? d.contact.externalId ?? null,
      hubspotStatus: isConflict ? 'existed' : 'created_or_updated'
    }
  }];
} else {
  const errDetail = {
    destination: 'hubspot',
    statusCode,
    message: body.message ?? body.error ?? 'unknown error',
    category: body.category ?? null
  };
  return [{
    json: {
      ...d,
      destinations: { ...d.destinations, hubspot: 'failed' },
      errors: [...(d.errors ?? []), errDetail]
    }
  }];
}

/*
 * FINAL SYNC STATUS EVALUATOR
 * ──────────────────────────────────────────────────────────────────
 * Computes the overall sync outcome across all destinations
 * and prepares the structured API response.
 */

const d = $input.first().json;

const allSucceeded  = d.destinations.hubspot !== 'failed' && d.destinations.sheets !== 'failed';
const anySucceeded  = d.destinations.hubspot !== 'failed' || d.destinations.sheets !== 'failed';
const noneSucceeded = !anySucceeded;

const overallStatus = allSucceeded ? 'full_success'
  : anySucceeded   ? 'partial_success'
  : 'failed';

const httpStatusCode = allSucceeded ? 200 : anySucceeded ? 207 : 500;

return [{
  json: {
    ...d,
    syncResult: {
      overallStatus,
      httpStatusCode,
      destinations: d.destinations,
      errors:       d.errors,
      syncId:       d.syncId,
      traceId:      d.traceId
    }
  }
}];
